package com.baize.flux.connector.jdbc;
import com.baize.flux.api.source.*; import com.baize.flux.api.table.*; import java.sql.*; import java.util.*;
final class JdbcSource implements Source { private final Map<String,String> o; private final TableSchema schema; JdbcSource(Map<String,String> options){o=Map.copyOf(options); schema=discoverSchema();} private Connection connect() throws SQLException{return DriverManager.getConnection(req("url"),o.getOrDefault("username",""),o.getOrDefault("password",""));} private String req(String key){var v=o.get(key);if(v==null)throw new IllegalArgumentException("jdbc source needs "+key);return v;} private TableSchema discoverSchema(){try(var c=connect();var s=c.createStatement();var r=s.executeQuery(req("query"))){var m=r.getMetaData();var cols=new ArrayList<String>();for(int i=1;i<=m.getColumnCount();i++)cols.add(m.getColumnLabel(i));return new TableSchema(cols);}catch(SQLException e){throw new IllegalArgumentException("Cannot read JDBC source schema",e);}} public TableSchema producedSchema(){return schema;} public List<SourceSplit> planSplits(){return List.of(new JdbcSplit("jdbc-single"));} public SourceReader createReader(SourceSplit split){return new JdbcReader();} private record JdbcSplit(String splitId) implements SourceSplit {}
 private final class JdbcReader implements SourceReader { Connection c; Statement s; ResultSet r; boolean done; public void open() throws SQLException {c=connect();s=c.createStatement(ResultSet.TYPE_FORWARD_ONLY,ResultSet.CONCUR_READ_ONLY);s.setFetchSize(Integer.parseInt(o.getOrDefault("fetch-size","1000")));r=s.executeQuery(req("query"));} public SourceResult poll(int batchSize) throws SQLException {if(done)return new SourceResult(null,true);var rows=new ArrayList<FluxRow>();while(rows.size()<batchSize&&r.next()){var values=new ArrayList<Object>();for(int i=1;i<=schema.columns().size();i++)values.add(r.getObject(i));rows.add(new FluxRow(values));}done=rows.size()<batchSize;return new SourceResult(new RowBatch(schema,rows),done);} public void close() throws SQLException {if(r!=null)r.close();if(s!=null)s.close();if(c!=null)c.close();} }
}
